args:
Add-Type -TypeDefinition @'
using System;
using System.Runtime.InteropServices;
public static class KeyStateReader {
  [DllImport("user32.dll")]
  public static extern short GetAsyncKeyState(int vKey);
}
'@
$states = @(
  [ordered]@{ name='CTRL'; vk='0x11'; raw=[KeyStateReader]::GetAsyncKeyState(0x11) },
  [ordered]@{ name='SHIFT'; vk='0x10'; raw=[KeyStateReader]::GetAsyncKeyState(0x10) },
  [ordered]@{ name='ALT'; vk='0x12'; raw=[KeyStateReader]::GetAsyncKeyState(0x12) }
) | ForEach-Object { [pscustomobject]@{ name=$_.name; vk=$_.vk; raw=$_.raw; down=(($_.raw -band 0x8000) -ne 0) } }
$states | ConvertTo-Json -Compress
